# fzf helpers for Entire CLI sessions.
#
# Usage:
#   etf    # session picker -> action picker (resume/explain/checkpoints/info/stop/clean)
#   etfd   # entire dispatch --local
#   etfr   # pick branch, resume session, then reopen the matching agent when supported

_entire_session_list() {
  command entire session list --json 2>/dev/null |
    jq -r '
      def ts_parts($ts):
        ($ts | tostring | try capture("^(?<y>[0-9]{4})-(?<m>[0-9]{2})-(?<d>[0-9]{2})[T ](?<h>[0-9]{2}):(?<min>[0-9]{2})") catch null);
      def fmt($ts):
        (ts_parts($ts) as $p | if $p == null then "" else "\($p.m)-\($p.d) \($p.h):\($p.min)" end);
      def year($ts):
        (ts_parts($ts) as $p | if $p == null then "" else $p.y end);
      .[] |
      [
        (.session_id // ""),
        (.status // ""),
        (.agent // ""),
        (fmt(.started_at // .last_active // "")),
        (fmt(.ended_at // "") // "-" | if . == "" then "-" else . end),
        (year(.started_at // .last_active // ""))
      ] | @tsv
    '
}

_entire_session_table() {
  _entire_session_list |
    awk -F '\t' '
      BEGIN {
        printf "__HEADER__\t%10s\t%14s\t%14s\t%14s\t%6s\n", "status", "agent", "started_at", "ended_at", "year"
      }
      {
        printf "%s\t%10s\t%14s\t%14s\t%14s\t%6s\n", $1, $2, $3, $4, $5, $6
      }
    '
}

_entire_session_fzf() {
  local preview_window="$1"

  _entire_session_table |
    fzf --ansi \
      --header-lines=1 \
      --with-nth=2.. \
      --delimiter=$'\t' \
      --prompt='entire session> ' \
      --footer='Enter: select session | Ctrl-/: toggle preview' \
      --bind='ctrl-/:toggle-preview' \
      --preview='entire session info {1} --json 2>/dev/null | jq -C . || true' \
      --preview-window="$preview_window"
}

_entire_action_pick() {
  printf '%s\n' \
    'resume       : resume session and reopen matching agent' \
    'explain      : explain latest checkpoint' \
    'checkpoints  : pick checkpoint to explain' \
    'info         : session info' \
    'stop         : stop session' \
    'clean        : entire clean --session' |
    fzf --ansi \
      --prompt='entire action> ' \
      --delimiter=':' \
      --with-nth=1,2 \
      --height=50% \
      --reverse \
      --footer='Enter: run selected action'
}

_entire_branch_pick() {
  local current_branch selected
  current_branch=$(git branch --show-current 2>/dev/null)

  selected=$(
    git for-each-ref --format='%(refname)' --sort=-committerdate refs/heads refs/remotes/origin 2>/dev/null |
      sed -e '/^refs\/remotes\/origin\/HEAD$/d' -e 's#^refs/heads/##' -e 's#^refs/remotes/origin/##' |
      awk -v cur="$current_branch" 'NF && $0 !~ /^entire\// && !seen[$0]++ { printf "%s\t%s\n", ($0 == cur ? "*" : " "), $0 }' |
      fzf --ansi \
        --delimiter=$'\t' \
        --with-nth=1,2 \
        --prompt='entire branch> ' \
        --height=40% \
        --reverse \
        --preview='git -c color.ui=always log --color=always --oneline --decorate -n 20 {2} 2>/dev/null || git -c color.ui=always log --color=always --oneline --decorate -n 20 origin/{2} 2>/dev/null || echo "No commit preview available"' \
        --preview-window='down:60%:wrap' \
        --footer='Enter: run entire session resume on selected branch'
  ) || return

  [[ -n "$selected" ]] || return
  cut -f2 <<< "$selected"
}

_entire_checkpoint_list_by_session() {
  local session_id
  session_id="$1"

  [[ -n "$session_id" ]] || return 1
  command entire checkpoint list --session "$session_id"
}

_entire_checkpoint_table_by_session() {
  _entire_checkpoint_list_by_session "$1" |
    awk '
      BEGIN {
        reset = "\033[0m"
        checkpoint_id_color = ENVIRON["ENTIRE_ZSH_CHECKPOINT_ID_COLOR"]
        if (ENVIRON["NO_COLOR"] != "") {
          checkpoint_id_color = ""
          reset = ""
        } else if (checkpoint_id_color == "") {
          checkpoint_id_color = "\033[33m"
        }
        printf "%s\t%s\t%s\n", "checkpoint_id", "checkpoint_id", "message"
      }
      /^●[[:space:]]+/ {
        checkpoint_id = $2
        message = $0
        sub(/^●[[:space:]]+[^[:space:]]+[[:space:]]+/, "", message)
        printf "%s\t%s\t%s\n", checkpoint_id, checkpoint_id_color checkpoint_id reset, message
      }
    '
}

_entire_checkpoint_id_from_line() {
  awk '{ if ($1 == "●") print $2; else print $1; exit }'
}

_entire_latest_checkpoint_id_by_session() {
  local session_id checkpoint_id
  session_id="$1"

  [[ -n "$session_id" ]] || return 1

  checkpoint_id=$(
    _entire_checkpoint_list_by_session "$session_id" |
      awk '/^●[[:space:]]+/ { print; exit }' |
      _entire_checkpoint_id_from_line
  )

  [[ -n "$checkpoint_id" ]] || {
    print -u2 'No checkpoint found for selected session.'
    return 1
  }

  print -r -- "$checkpoint_id"
}

_entire_checkpoint_pick_by_session() {
  local session_id line checkpoint_id
  session_id="$1"

  [[ -n "$session_id" ]] || return 1

  line=$(
    _entire_checkpoint_table_by_session "$session_id" |
      fzf --ansi \
        --header-lines=1 \
        --with-nth=2,3 \
        --delimiter=$'\t' \
        --prompt='entire checkpoint> ' \
        --height=50% \
        --reverse \
        --preview='entire checkpoint explain {1} 2>/dev/null || true' \
        --preview-window='down:70%:wrap' \
        --footer='Enter: explain selected checkpoint'
  ) || return

  [[ -n "$line" ]] || return
  checkpoint_id=$(print -r -- "$line" | _entire_checkpoint_id_from_line)
  [[ -n "$checkpoint_id" ]] || return 1

  print -r -- "$checkpoint_id"
}

_entire_branch_by_session() {
  local session_id worktree_path branch
  session_id="$1"

  [[ -n "$session_id" ]] || return 1

  worktree_path=$(command entire session info "$session_id" --json 2>/dev/null | jq -r '.worktree_path // empty')

  [[ -n "$worktree_path" ]] || {
    print -u2 "Could not find worktree_path for session: $session_id"
    return 1
  }

  branch=$(git -C "$worktree_path" branch --show-current 2>/dev/null)

  [[ -n "$branch" ]] || {
    print -u2 "Could not determine branch for session: $session_id"
    return 1
  }

  print -r -- "$branch"
}

_entire_resume_and_agent() {
  local target output session_id agent continue_command
  target="$1"

  [[ -n "$target" ]] || return 1

  output=$(command entire session resume "$target") || {
    print -r -- "$output"
    return 1
  }

  print -r -- "$output"

  continue_command=$(awk '/^[[:space:]]*(claude|codex)[[:space:]]+/ { sub(/^[[:space:]]+/, ""); print; exit }' <<< "$output")

  case "$continue_command" in
    claude\ -r\ *)
      session_id=${continue_command##* }
      ;;
    codex\ resume\ *)
      session_id=${continue_command#codex resume }
      session_id=${session_id%% *}
      ;;
  esac

  if [[ -z "$session_id" && "$target" == [0-9a-fA-F]##-[0-9a-fA-F-]## ]]; then
    session_id="$target"
  fi

  [[ -n "$session_id" ]] || {
    print -u2 'Could not determine resumed session id.'
    return 1
  }

  agent=$(command entire session info "$session_id" --json 2>/dev/null | jq -r '.agent // empty')

  case "$agent" in
    'Claude Code')
      command claude -r "$session_id"
      ;;
    'Codex'|'OpenAI Codex')
      command codex resume "$session_id"
      ;;
    'GitHub Copilot'|'Copilot')
      command copilot --resume="$session_id"
      ;;
    *)
      print "Session restored for agent: ${agent:-unknown}"
      ;;
  esac
}

_entire_session_action() {
  local line session_id checkpoint_id action branch

  line=$(_entire_session_fzf 'down:70%:wrap') || return
  [[ -n "$line" ]] || return

  session_id=$(cut -f1 <<< "$line")
  action=$(_entire_action_pick | awk -F ':' '{gsub(/^[[:space:]]+|[[:space:]]+$/, "", $1); print $1}') || return

  case "$action" in
    resume)
      branch=$(_entire_branch_by_session "$session_id") || return
      _entire_resume_and_agent "$branch"
      ;;
    explain)
      checkpoint_id=$(_entire_latest_checkpoint_id_by_session "$session_id") || return
      command entire checkpoint explain "$checkpoint_id"
      ;;
    checkpoints)
      checkpoint_id=$(_entire_checkpoint_pick_by_session "$session_id") || return
      command entire checkpoint explain "$checkpoint_id"
      ;;
    info)
      command entire session info "$session_id"
      ;;
    stop)
      command entire session stop "$session_id"
      ;;
    clean)
      command entire clean --session "$session_id"
      ;;
    *)
      return 1
      ;;
  esac
}

etf() {
  _entire_session_action
}

etfd() {
  command entire dispatch --local
}

etfr() {
  local branch
  branch=$(_entire_branch_pick) || return
  [[ -n "$branch" ]] || return
  _entire_resume_and_agent "$branch"
}

