      def fmt($ts):
        (ts_parts($ts) as $p | if $p == null then "" else "\($p.m)-\($p.d) \($p.h):\($p.min)" end);
      def year($ts):
        (ts_parts($ts) as $p | if $p == null then "" else $p.y end);
      .[] |
      [
        (.session_id // ""),
        (.status // ""),
        (.agent // ""),
        (fmt(.started_at // .last_active // "")),
        (fmt(.ended_at // "") // "-" | if . == "" then "-" else . end),
        (year(.started_at // .last_active // ""))
      ] | @tsv
    '
